weights.
*/
static void InitLists(
    NodePool *pool, const Node *leaves, int maxbits, Node *(*lists)[2])
{
    int i;
    Node *node0 = pool->next++;
    Node *node1 = pool->next++;
    InitNode(leaves[0].weight, 1, 0, node0);
    InitNode(leaves[1].weight, 2, 0, node1);
