        Node *oldchain = lists[index][1]->tail;

        lists[index][1] = newchain;
        newchain->count = lastcount + 1;
        newchain->tail = oldchain;
    }
    else
    {
        lists[index][1]->tail = lists[index - 1][1];
    }
}

